    // Mutated: /#.$/ does NOT match bare '#' (needs char after #), stays as '#'
    // '#' -> prepended -> 'http://#' -> parsed differently
    const resultOriginal = parse('#');
    // In original, '#' becomes '' becomes 'http://' - host is null
